import functools

def validate_with(validator_func):
    """
    Bir fonksiyonun çağrılmadan önce belirli bir doğrulama mantığını uygulamak için kullanılan bir dekore edicidir.

    Kullanım:
    @validate_with(dogrulama_fonksiyonu)
    def islenecek_fonksiyon(...):
        pass

    `dogrulama_fonksiyonu`, dekore edilen fonksiyon ile aynı argümanları almalıdır.
    Başarılı doğrulama durumunda `True` döndürmeli veya başarısızlık durumunda bir hata fırlatmalıdır.
    Eğer `False` dönerse, bir `ValueError` fırlatılır.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            try:
                validation_result = validator_func(*args, **kwargs)
                if validation_result is False:
                    raise ValueError(f"Validation failed for {func.__name__} due to validator {validator_func.__name__}.")
            except Exception as e:
                raise type(e)(f"Validation failed for {func.__name__}: {e}") from e

            return func(*args, **kwargs)
        return wrapper
    return decorator
